from __future__ import annotations
import time
from dataclasses import dataclass
from typing import Optional

# Required metadata fields on every chunk in the provenance registry
REQUIRED_CHUNK_FIELDS = {
    "chunk_id", "doc_id", "sensitivity_label",
    "source_uri", "indexed_utc", "embedding_model",
}

@dataclass
class CompletenessResult:
    total_chunks:       int
    complete_chunks:    int
    incomplete_chunks:  list[str]   # chunk_ids missing one or more fields
    completeness_pct:   float

def compute_completeness(chunk_registry_rows: list[dict]) -> CompletenessResult:
    total = len(chunk_registry_rows)
    complete = 0
    incomplete = []
    for row in chunk_registry_rows:
        if all(row.get(f) for f in REQUIRED_CHUNK_FIELDS):
            complete += 1
        else:
            incomplete.append(row.get("chunk_id", "unknown"))
    return CompletenessResult(
        total_chunks=total,
        complete_chunks=complete,
        incomplete_chunks=incomplete,
        completeness_pct=round(complete / total * 100, 2) if total else 0.0,
    )


@dataclass
class FreshnessResult:
    total_docs:     int
    fresh_docs:     int
    stale_docs:     list[str]   # doc_ids past their max_age_days
    freshness_pct:  float

def compute_freshness(
    decisions: dict[str, "DomainStewardDecision"],
    now: Optional[float] = None,
) -> FreshnessResult:
    now = now or time.time()
    total = len(decisions)
    fresh = 0
    stale: list[str] = []
    for doc_id, decision in decisions.items():
        if now <= decision.review_by_utc:
            fresh += 1
        else:
            stale.append(doc_id)
    return FreshnessResult(
        total_docs=total,
        fresh_docs=fresh,
        stale_docs=stale,
        freshness_pct=round(fresh / total * 100, 2) if total else 0.0,
    )

from __future__ import annotations
import random
from dataclasses import dataclass, field
from typing import Optional

SAMPLING_WEIGHTS: dict[str, float] = {
    "PUBLIC":       0.05,
    "INTERNAL":     0.10,
    "RESTRICTED":   0.25,
    "CONFIDENTIAL": 0.35,
    "REGULATED":    0.25,
}

@dataclass
class LabelSampleItem:
    doc_id:          str
    source_title:    str
    current_label:   str
    steward_verdict: Optional[str] = None   # "correct" | "should_be_<label>"
    requires_correction: bool = False

@dataclass
class LabelAccuracyResult:
    sample_size:     int
    correct_count:   int
    corrections:     list[LabelSampleItem]   # items where verdict != "correct"
    accuracy_pct:    float

def draw_label_audit_sample(
    doc_registry: list[dict],   # list of {doc_id, source_title, sensitivity_label}
    target_sample_size: int = 50,
    seed: Optional[int] = None,
) -> list[LabelSampleItem]:
    """Stratified sample weighted toward higher-risk sensitivity tiers."""
    rng = random.Random(seed)
    by_label: dict[str, list[dict]] = {}
    for doc in doc_registry:
        label = doc.get("sensitivity_label", "INTERNAL")
        by_label.setdefault(label, []).append(doc)

    samples: list[LabelSampleItem] = []
    total_weight = sum(SAMPLING_WEIGHTS.get(l, 0.1) * len(docs)
                       for l, docs in by_label.items())

    for label, docs in by_label.items():
        weight = SAMPLING_WEIGHTS.get(label, 0.1)
        n = max(1, round(target_sample_size * weight * len(docs) / total_weight))
        chosen = rng.sample(docs, min(n, len(docs)))
        for d in chosen:
            samples.append(LabelSampleItem(
                doc_id=d["doc_id"],
                source_title=d.get("source_title", ""),
                current_label=label,
            ))
    return samples[:target_sample_size]


def score_label_accuracy(items: list[LabelSampleItem]) -> LabelAccuracyResult:
    rated = [i for i in items if i.steward_verdict is not None]
    if not rated:
        raise ValueError("No steward verdicts recorded yet")
    correct = sum(1 for i in rated if i.steward_verdict == "correct")
    corrections = [i for i in rated if i.steward_verdict != "correct"]
    return LabelAccuracyResult(
        sample_size=len(rated),
        correct_count=correct,
        corrections=corrections,
        accuracy_pct=round(correct / len(rated) * 100, 2),
    )

from __future__ import annotations
from dataclasses import dataclass
from enum import Enum
from typing import Optional

DIMENSION_WEIGHTS = {
    "completeness":        0.25,
    "freshness":           0.25,
    "label_accuracy":      0.30,
    "retrieval_coverage":  0.10,
    "consistency":         0.10,
}

class QualityStatus(str, Enum):
    GREEN = "green"   # at or above target
    AMBER = "amber"   # below target but above red threshold
    RED   = "red"     # below red threshold — requires immediate action

THRESHOLDS: dict[str, dict[str, float]] = {
    "completeness":       {"green": 99.0, "amber": 95.0},
    "freshness":          {"green": 95.0, "amber": 80.0},
    "label_accuracy":     {"green": 98.0, "amber": 90.0},
    "retrieval_coverage": {"green": 85.0, "amber": 70.0},
    "consistency":        {"green": 97.0, "amber": 90.0},
}

def classify_metric(dimension: str, value: float) -> QualityStatus:
    t = THRESHOLDS.get(dimension, {"green": 95.0, "amber": 80.0})
    if value >= t["green"]:
        return QualityStatus.GREEN
    if value >= t["amber"]:
        return QualityStatus.AMBER
    return QualityStatus.RED


@dataclass
class KBQualityReport:
    kb_id:                str
    period_end_utc:       float
    completeness_pct:     float
    freshness_pct:        float
    label_accuracy_pct:   float
    retrieval_coverage_pct: float
    consistency_pct:      float

    def composite_score(self) -> float:
        metrics = {
            "completeness":        self.completeness_pct,
            "freshness":           self.freshness_pct,
            "label_accuracy":      self.label_accuracy_pct,
            "retrieval_coverage":  self.retrieval_coverage_pct,
            "consistency":         self.consistency_pct,
        }
        return round(sum(v * DIMENSION_WEIGHTS[k] for k, v in metrics.items()), 2)

    def dimension_statuses(self) -> dict[str, QualityStatus]:
        return {
            "completeness":        classify_metric("completeness",       self.completeness_pct),
            "freshness":           classify_metric("freshness",          self.freshness_pct),
            "label_accuracy":      classify_metric("label_accuracy",     self.label_accuracy_pct),
            "retrieval_coverage":  classify_metric("retrieval_coverage", self.retrieval_coverage_pct),
            "consistency":         classify_metric("consistency",        self.consistency_pct),
        }

    def overall_status(self) -> QualityStatus:
        statuses = self.dimension_statuses().values()
        if any(s == QualityStatus.RED for s in statuses):
            return QualityStatus.RED
        if any(s == QualityStatus.AMBER for s in statuses):
            return QualityStatus.AMBER
        return QualityStatus.GREEN

    def requires_ingestion_block(self) -> bool:
        """Block new ingestion when completeness or label accuracy is RED."""
        return (
            classify_metric("completeness",    self.completeness_pct)    == QualityStatus.RED or
            classify_metric("label_accuracy",  self.label_accuracy_pct)  == QualityStatus.RED
        )
